// Entity
@Entity
@Table(name = "users")
public class User {
  @Id @GeneratedValue(strategy = GenerationType.IDENTITY)
  private Long id;
  @Column(nullable = false, unique = true) private String email;
  @Column(nullable = false) private String name;
  private Instant createdAt = Instant.now();
  // getters / setters / no-arg ctor omitted
}

// Repository ã Spring Data auto-implements at runtime.
public interface UserRepository extends JpaRepository<User, Long> {
  Optional<User> findByEmail(String email);
  boolean existsByEmail(String email);
}

// Service ã business logic; transactional.
@Service
public class UserService {
  private final UserRepository users;
  public UserService(UserRepository users) { this.users = users; }

  public User getById(Long id) {
    return users.findById(id)
        .orElseThrow(() -> new NotFoundException("User " + id));
  }

  @Transactional
  public User create(CreateUserRequest req) {
    if (users.existsByEmail(req.email())) {
      throw new ConflictException("Email already exists");
    }
    var user = new User();
    user.setEmail(req.email());
    user.setName(req.name());
    return users.save(user);
  }

  @Transactional
  public void delete(Long id) {
    users.deleteById(id);
  }
}

// Controller ã thin. Just wire HTTP to the service.
@RestController
@RequestMapping("/api/v1/users")
public class UserController {
  private final UserService svc;
  public UserController(UserService svc) { this.svc = svc; }

  @GetMapping("/{id}")
  public UserDto get(@PathVariable Long id) {
    return UserDto.from(svc.getById(id));
  }

  @PostMapping
  public ResponseEntity<UserDto> create(@Valid @RequestBody CreateUserRequest req) {
    var u = svc.create(req);
    return ResponseEntity.created(URI.create("/api/v1/users/" + u.getId()))
        .body(UserDto.from(u));
  }

  @DeleteMapping("/{id}")
  public ResponseEntity<Void> delete(@PathVariable Long id) {
    svc.delete(id);
    return ResponseEntity.noContent().build();
  }
}

// DTO + validated request record
public record CreateUserRequest(
    @NotBlank String name,
    @Email @NotBlank String email
) {}

public record UserDto(Long id, String name, String email, Instant createdAt) {
  public static UserDto from(User u) {
    return new UserDto(u.getId(), u.getName(), u.getEmail(), u.getCreatedAt());
  }
}

// Global error handler ã maps exceptions to HTTP responses.
@RestControllerAdvice
public class ErrorHandler {
  @ExceptionHandler(NotFoundException.class)
  public ResponseEntity<?> notFound(NotFoundException e) {
    return ResponseEntity.status(404).body(Map.of("code", "NOT_FOUND", "message", e.getMessage()));
  }
  @ExceptionHandler(ConflictException.class)
  public ResponseEntity<?> conflict(ConflictException e) {
    return ResponseEntity.status(409).body(Map.of("code", "CONFLICT", "message", e.getMessage()));
  }
  @ExceptionHandler(MethodArgumentNotValidException.class)
  public ResponseEntity<?> validation(MethodArgumentNotValidException e) {
    var errors = e.getBindingResult().getFieldErrors().stream()
        .collect(Collectors.toMap(FieldError::getField, DefaultMessageSourceResolvable::getDefaultMessage));
    return ResponseEntity.badRequest().body(Map.of("code", "VALIDATION", "fields", errors));
  }
}

